INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c6fb568f-2e9a-4b26-b6c6-74c0e38205c9', 'benefits', 'https://www.arbeitsagentur.de/arbeitslosengeld-2', 'active', 'Bürgergeld (Arbeitslosengeld II)', '2026-03-06T09:19:54.0401780+01:00', '{"title":{"de":"Bürgergeld (Arbeitslosengeld II)","easy_de":"Bürgergeld"},"summary":{"de":"Bürgergeld ist eine Leistung der Grundsicherung für erwerbsfähige Menschen mit zu geringem Einkommen oder ohne Arbeit und deckt Regelbedarf sowie angemessene Wohnkosten ab."},"content":{"de":"Die Informationsseite der Bundesagentur für Arbeit erläutert Anspruch, Antrag und zentrale Rahmenbedingungen für Bürgergeld. Sie verweist auf Zuständigkeiten der Jobcenter und auf Pflichten sowie Mitwirkungsanforderungen im Leistungsbezug."},"topics":["financial_support","employment"],"tags":["means_tested","application_required"],"targetGroups":["unemployed","single_parents","families"],"id":"c6fb568f-2e9a-4b26-b6c6-74c0e38205c9","url":"https://www.arbeitsagentur.de/arbeitslosengeld-2","status":"active","firstSeen":"2026-03-01T18:38:38.422093+00:00","lastSeen":"2026-03-01T18:38:38.422108+00:00","sourceUnavailable":false,"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslosengeld-2","crawledAt":"2026-03-01T18:38:38.422182Z","crawlId":"arbeitsagentur-1772390318","checksum":"ffc0d29466a4c3d036b2d235d5654104d0978487c703a43f8b567679ad3963fc"},"qualityScores":{"iqs":78.12,"ais":46.5,"computedAt":"2026-03-01T18:38:38.422231+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
