INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a6f576ba-c5f0-4ff2-8f63-aa56abbb56fd', 'benefits', 'https://www.arbeitsagentur.de/familie-und-kinder', 'active', 'Familie und Kinder (Leistungsüberblick)', '2026-03-06T09:19:54.0607460+01:00', '{"id":"a6f576ba-c5f0-4ff2-8f63-aa56abbb56fd","title":{"de":"Familie und Kinder (Leistungsüberblick)","easy_de":"Hilfe für Familien"},"summary":{"de":"Die Seite bietet einen zentralen Einstieg zu Kindergeld, Kinderzuschlag und weiteren Unterstützungsangeboten für Familien."},"content":{"de":"Sie enthält Schnellzugriffe auf eServices, Leistungsinformationen und weiterführende Hilfen für Eltern. Zusätzlich verweist sie auf regionale Familienkassen und ergänzende staatliche Unterstützungsangebote."},"url":"https://www.arbeitsagentur.de/familie-und-kinder","topics":["financial_support","family"],"tags":["application_required","means_tested"],"targetGroups":["families","single_parents"],"status":"active","firstSeen":"2026-03-01T20:10:00Z","lastSeen":"2026-03-01T20:10:00Z","sourceUnavailable":false,"provenance":{"source":"https://www.arbeitsagentur.de/familie-und-kinder","crawlId":"manual-curation-20260301-realdata-v1","checksum":"8af7ad26c31cda2283dc396969745688f58f74e826de8822d7405ea3d5f92931","crawledAt":"2026-03-01T20:10:00Z"},"qualityScores":{"iqs":79.8,"ais":51.2,"computedAt":"2026-03-01T20:10:00Z"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
